const F = {NAME:1,MAT:2,YEAR:3,PRES:4,LEN:5,DONG:6,PROJ:7,SCORE:8,GRADE:9,DE:10,TH:11,CO:12,OP:13,ST:14,COLOR:15,EXC:16,PT:17};

function getColor(s) {
  if (!s) return "#64748B";
  if (s < 120) return "#DC2626";
  if (s < 135) return "#EAB308";
  return "#16A34A";
}

function buildAcc(p) {
  const s = p[F.SCORE], a = 2025 - p[F.YEAR], e = p[F.EXC], pr = p[F.PRES];
  const blocks = [];
  if (e) blocks.push({
    t: "굴착이력 배관 - 외부충격 손상 위험",
    r: "굴착 진동/충격으로 배관 연결부 이완, 피복 손상, 미세 균열이 잠재합니다.",
    cases: [
      {y:"2025.06", l:"서울 서초구 교대역", d:"굴착기가 중압배관 직접 타격, 지하철 2,3호선 무정차 통과, 서초대로 전면 통제"},
      {y:"2024 5건", l:"전국", d:"굴착센터 무신고 공사 중 배관 파손 5건 연속. 위반시 2년이하 징역 또는 2천만원 벌금"}
    ]
  });
  if (p[F.MAT] === "PLP" && a >= 15) blocks.push({
    t: `PLP 강관 ${a}년 경과 - 부식/균열 위험`,
    r: "피복 노화 시 수분 침투로 강관 외면 부식이 진행됩니다. 20년 이상은 핀홀 누출 위험이 높아요.",
    cases: [
      {y:"2025", l:"전국", d:"PLP관 31년 이상 배관 3,321km(13.8%). 자연균열 발생 우려 - 에너지신문"},
      {y:"2020~2024", l:"전국", d:"5년간 시설미비 사고 연평균 15건. 노후 배관 피복 손상이 주요 원인"}
    ]
  });
  if (pr === "중압") blocks.push({
    t: "중압 배관 - 파열 시 광역 피해",
    r: "중압 배관 파열 시 저압 대비 분출량이 수십배. 인근 광역 피해 및 2차 화재 위험.",
    cases: [
      {y:"1995.04.28", l:"대구 달서구 상인동", d:"무단 천공으로 중압관 파손. 사망 101명, 부상 202명, 피해액 540억원. 국내 최대 사고"},
      {y:"2024", l:"전국", d:"타공사 사고 6건 중 중압 이상 배관 피해 포함. 굴착시 가스안전공사 의무 입회 시행"}
    ]
  });
  if (s && s < 120) blocks.push({
    t: "보통이하 등급 - 복합 위험 중첩",
    r: `현재 배관은 ${s}점으로 보통이하 등급입니다. 복수 위험인자가 동시에 낮은 상태로 즉시 정밀안전진단이 필요합니다.`,
    cases: [
      {y:"1995.04.28", l:"대구 상인동", d:"복합 위험 중첩으로 사망 101명, 피해액 540억원. 위험요인 중첩이 대형 사고로 이어진 사례"},
      {y:"2020~2024", l:"전국", d:"가스사고 원인: 시설미비 15건, 제품노후 14건, 타공사 6건. 복합위험 배관 사고 발생률 3배"}
    ]
  });
  if (!blocks.length) blocks.push({
    t: "현재 등급 안정 - 정기 모니터링 유지",
    r: "안정적인 상태이지만 외부 환경 변화에 의해 갑작스러운 상태 변화가 발생할 수 있습니다.",
    cases: [
      {y:"2024", l:"전국", d:"2024년 도시가스 사고 17건. 양호 등급도 굴착공사 등 외부 요인으로 사고 발생 가능"},
      {y:"2020~2024", l:"전국", d:"5년간 도시가스 사고 79건. 정기점검(기밀시험 15년후 5년마다) 필수"}
    ]
  });
  return blocks;
}

